// Description: Discovers PromQL query instances from device properties (thanos.query.N.*).
// Description: Each property set becomes an LM instance grouped by auto.query.group.

// Iterate through numbered query properties (1-99)
for (int i = 1; i <= 99; i++) {
    def name = hostProps.get("thanos.query.${i}.name")
    if (!name) break

    def promql = hostProps.get("thanos.query.${i}.promql")
    def group = hostProps.get("thanos.query.${i}.group") ?: "default"

    if (promql) {
        // URL-encode the promql value so that characters like = " { } & in PromQL
        // label filters do not break the key=value&key=value property format.
        // The collection script URL-decodes it before use.
        def encodedPromql = java.net.URLEncoder.encode(promql, "UTF-8")
        println "${name}##${name}##PromQL: ${promql}####auto.query.promql=${encodedPromql}&auto.query.group=${group}"
    }
}

return 0

