// Description: Executes a PromQL query against a Thanos endpoint and returns the numeric result.
// Description: Each instance runs one query defined by device properties (thanos.query.N.*).
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("thanos.host")
def token = hostProps.get("thanos.pass")
def port = hostProps.get("thanos.port") ?: "443"
def useSsl = (hostProps.get("thanos.ssl") ?: "true").toLowerCase() == "true"

// The PromQL query for this instance is stored as a URL-encoded instance-level property.
// AD script encodes it to avoid = and & in PromQL breaking the property format.
def promqlRaw = instanceProps.get("auto.query.promql")
def promql = promqlRaw ? java.net.URLDecoder.decode(promqlRaw, "UTF-8") : null

if (!host || !token || !promql) {
    println("value:NaN")
    println("query_status:2")
    return 0
}

// Trust all certs (self-signed common in OpenShift/internal clusters)
def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

try {
    def encoded = java.net.URLEncoder.encode(promql, "UTF-8")
    def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
    def conn = url.openConnection()
    conn.setRequestProperty("Authorization", "Bearer ${token}")
    conn.setRequestProperty("Accept", "application/json")
    conn.setConnectTimeout(30000)
    conn.setReadTimeout(30000)

    if (conn.responseCode == 200) {
        def response = conn.inputStream.text
        def json = new JsonSlurper().parseText(response)

        if (json.status == "success" && json.data?.result?.size() > 0) {
            // For instant queries, result[0].value[1] holds the scalar value
            def val = json.data.result[0].value[1]
            if (val != null && val.toString().isNumber()) {
                println("value:${val}")
                println("query_status:0")
            } else {
                // Query returned non-numeric (e.g. NaN, Inf, string)
                println("value:NaN")
                println("query_status:1")
            }
        } else {
            // Query succeeded but returned empty result set
            println("value:NaN")
            println("query_status:1")
        }
    } else {
        // HTTP error from Thanos
        println("value:NaN")
        println("query_status:2")
    }
} catch (Exception e) {
    println("value:NaN")
    println("query_status:2")
}

return 0
